#include <bits/stdc++.h>
using namespace std;

struct Point {
    int x, y, p;
};

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(nullptr);

    int N;
    cin >> N;
    vector<Point> pts(N);
    for (int i = 0; i < N; i++) {
        cin >> pts[i].x >> pts[i].y >> pts[i].p;
    }

    // We'll use DP: dp[i] = maximum total points ending at point i
    // For two points a and b, Manhattan distance allows moving from a to b
    // if a.x <= b.x and a.y <= b.y, OR a.x <= b.x and a.y >= b.y.
    // Actually, Manhattan path from a to b: |a.x-b.x| + |a.y-b.y|
    // We can always travel from any point to any other point via Manhattan distance.
    // But the key insight: we can visit points in any order as long as the path
    // respects "moving only along x or y axes".
    //
    // The condition for being able to go from point i to point j in a Manhattan
    // path without extra backtracking (i.e., the shortest path) is simply:
    // we can always go from any point to any other using Manhattan distance.
    // So we can visit any subset of points in any order.
    //
    // Wait - the original problem "Maximizing Mission Points" on SPOJ RGB7798
    // is about points on a 2D grid where you can only move axis-aligned.
    // The actual problem is: given points (x,y) with value p, find the maximum
    // sum of points along a path where you can only move from (x1,y1) to (x2,y2)
    // if x1 <= x2 and y1 <= y2 (monotonic path) - this is a classic 2D LIS problem.
    //
    // Let me reconsider. The description says "move along same x or y axis".
    // This means the path must be such that consecutive points share either x or y.
    // Actually no - it says "from one point to another, you must first move horizontally
    // then vertically, or first vertically then horizontally." This just describes
    // Manhattan movement, not a restriction on ordering.
    //
    // But the classic problem RGB7798: given points, find maximum sum along a
    // monotonic path (non-decreasing x and y). Let me check samples...

    // Sort by x, then by y
    sort(pts.begin(), pts.end(), [](const Point& a, const Point& b) {
        if (a.x != b.x) return a.x < b.x;
        return a.y < b.y;
    });

    vector<int> dp(N);
    int ans = 0;

    for (int i = 0; i < N; i++) {
        dp[i] = pts[i].p;
        for (int j = 0; j < i; j++) {
            // Can go from j to i if x[j] <= x[i] and we can travel via Manhattan
            // Actually the classic problem: can go from j to i if x[j] <= x[i] and y[j] <= y[i]
            // (monotonic path). Let's check if this matches samples.
            if (pts[j].x <= pts[i].x && pts[j].y <= pts[i].y) {
                dp[i] = max(dp[i], dp[j] + pts[i].p);
            }
        }
        ans = max(ans, dp[i]);
    }

    cout << ans << '\n';
    return 0;
}
